definition.script:
import groovy.json.JsonSlurper
      import groovy.transform.Field

      def subTypeScript = getSubTypeScript()
      @Field  def OCTOPERF_AUTH_HEADER="Authorization: Bearer XXXXX";
      @Field def OCTOPERF_PROJECT_ID="BSruw44BqQahJeAt-mOY";
      @Field def OCTOPERF_USER_ID="B13yv44BafbDfoxhauJx";
      @Field def OCTOPERF_TRIGGER_VARIABLE_ID="GHEVl48B-ZTx-WvoinqY";
      @Field def OCTOPERF_TRIGGER_VARIABLE="at_trigger";

      pipeline {
      agent any
      //   triggers {
      //   parameterizedCron('''
      //   0 9 * * * %measurement=octoperf9
      //   0 10 * * * %measurement=octoperf10
      //   0 11 * * * %measurement=octoperf11
      //   ''')
      //   }
      options {
      timestamps()
      }
      parameters {
      // string(name: "scenario_id", defaultValue: "URGbL48BafbDfoxhuivo", description: "Octoperf test scenario id")
      string(name: "measurement", defaultValue: "octoperf", description: "Measurement id for Octoperf")
      activeChoice choiceType: 'PT_SINGLE_SELECT', filterLength: 1, filterable: false, name: 'scenario', randomName: 'choice-parameter-78492632647610', script: groovyScript(fallbackScript: [classpath: [], oldScript: '', sandbox: true, script: "return ['Select which type']"], script: [classpath: [], oldScript: '', sandbox: true, script: "return $subTypeScript"])

      }

      stages {
      stage('OctoPerf') {
      steps {
      script{
      SCENARIO_ID=params.scenario.split(":").last().trim().replace("[","").replace("]","").trim()
      echo "SCENARIO_ID=${SCENARIO_ID}"
      sh "curl -X 'PUT' 'https://api.octoperf.com/design/variables/$OCTOPERF_TRIGGER_VARIABLE_ID' -H 'accept: */*' -H '$OCTOPERF_AUTH_HEADER' -H 'Content-Type: application/json' -d '{  \"description\": \"\",  \"id\": \"$OCTOPERF_TRIGGER_VARIABLE_ID\",  \"name\": \"$OCTOPERF_TRIGGER_VARIABLE\",  \"projectId\": \"$OCTOPERF_PROJECT_ID\",  \"userId\": \"$OCTOPERF_USER_ID\",  \"variable\": {    \"@type\": \"ConstantVariable\",    \"value\": \"${params.measurement}\"}}'"
      sh "sed -i -e \"s/default_cpu_tag/${params.measurement}/g\" /share/telegraf.conf"
      sh "sed -i -e \"s/default_mem_tag/${params.measurement}/g\" /share/telegraf.conf"
      octoPerfTest credentialsId: 'octo', scenarioId: "${SCENARIO_ID}"
      }
      }
      post{
      always{
      script{
      sh "curl -X 'PUT' 'https://api.octoperf.com/design/variables/$OCTOPERF_TRIGGER_VARIABLE_ID' -H 'accept: */*' -H '$OCTOPERF_AUTH_HEADER' -H 'Content-Type: application/json' -d '{  \"description\": \"\",  \"id\": \"$OCTOPERF_TRIGGER_VARIABLE_ID\",  \"name\": \"$OCTOPERF_TRIGGER_VARIABLE\",  \"projectId\": \"$OCTOPERF_PROJECT_ID\",  \"userId\": \"$OCTOPERF_USER_ID\",  \"variable\": {    \"@type\": \"ConstantVariable\",    \"value\": \"jmeter\"}}'"
      sh "sed -i -e \"s/${params.measurement}/default_cpu_tag/g\" /share/telegraf.conf"
      sh "sed -i -e \"s/${params.measurement}/default_mem_tag/g\" /share/telegraf.conf"
      }
      }
      }
      }
      stage('Archive Artifacts') {
      steps {
      archiveArtifacts artifacts: '**/*.log',
      allowEmptyArchive: true,
      fingerprint: true,
      onlyIfSuccessful: false
      }
      }

      stage('JunitReport') {
      steps {
      junit 'junit-report.xml'
      }
      }

      stage('PerfReport') {
      steps {
      perfReport modeThroughput: true, sourceDataFiles: 'jtls/*.jtl'
      }
      }
      }

      }
      def getSubTypeScript() {
      def proc= ["curl", "--url", "https://api.octoperf.com/runtime/scenarios/by-project/$OCTOPERF_PROJECT_ID", "-H", "$OCTOPERF_AUTH_HEADER"].execute()
      proc.waitFor()
      def data = (List)new JsonSlurper().parseText(proc.text)
      data.sort{ a, b -> a.name <=> b.name  }
      return data.collect{t -> "\""+t["name"]+": ["+t["id"]+"]\""}.sort()
      }
